  1→import React, {useMemo, useState} from 'react';
  2→import {
  3→  FlatList,
  4→  Pressable,
  5→  ScrollView,
  6→  StyleSheet,
  7→  Text,
  8→  View,
  9→} from 'react-native';
 10→import {useInfiniteQuery, useMutation} from '@tanstack/react-query';
 11→import {BottomTabScreenProps} from '@react-navigation/bottom-tabs';
 12→import {CompositeScreenProps} from '@react-navigation/native';
 13→import {NativeStackScreenProps} from '@react-navigation/native-stack';
 14→import {SafeAreaView} from 'react-native-safe-area-context';
 15→import {PostCard} from '../../components/PostCard/PostCard';
 16→import {PostCardSkeleton} from '../../components/SkeletonLoader';
 17→import {CommentModal} from '../../components/Comments';
 18→import {RepostModal} from '../../components/RepostModal';
 19→import {Chip} from '../../components/Chip';
 20→import {EmptyState} from '../../components/EmptyState';
 21→import {PenIcon} from '../../components/icons';
 22→import {useAuth} from '../../features/auth/AuthProvider';
 23→import {useTheme} from '../../theme/ThemeProvider';
 24→import {fonts, typeScale} from '../../theme/typography';
 25→import {spacing, radii, shadows} from '../../theme/spacing';
 26→import {
 27→  mobileApi,
 28→  type CursorPage,
 29→  type JournalItem,
 30→} from '../../lib/api/mobileApi';
 31→import {socialApi} from '../../lib/api/socialApi';
 32→import {queryClient} from '../../lib/queryClient';
 33→import {useBookmarkMutation} from '../../hooks/useSocialMutations';
 34→import {
 35→  extractPlainText,
 36→  extractBannerImage,
 37→  resolveCount,
 38→  getNextCursor,
 39→} from '../../lib/utils/journalHelpers';
 40→import type {MainTabParamList, RootStackParamList} from '../../navigation/types';
 41→
 42→type Props = CompositeScreenProps<
 43→  BottomTabScreenProps<MainTabParamList, 'Home'>,
 44→  NativeStackScreenProps<RootStackParamList>
 45→>;
 46→
 47→const PAGE_SIZE = 10;
 48→
 49→const QUICK_ACTIONS = [
 50→  {key: 'all', label: 'All'},
 51→  {key: 'journal', label: 'Journals'},
 52→  {key: 'canvas', label: 'Canvas'},
 53→  {key: 'universe', label: 'Universe'},
 54→] as const;
 55→
 56→export function HomeFeedScreen({navigation}: Props) {
 57→  const {user, session} = useAuth();
 58→  const {colors} = useTheme();
 59→  const token = session?.access_token ?? '';
 60→  const [refreshing, setRefreshing] = useState(false);
 61→  const [activeFilter, setActiveFilter] = useState('all');
 62→  const [commentModal, setCommentModal] = useState<{postId: string; receiverId?: string; commentCount: number} | null>(null);
 63→  const [repostModal, setRepostModal] = useState<{journalId: string; title?: string; authorName?: string; authorAvatar?: string} | null>(null);
 64→
 65→  const feedQuery = useInfiniteQuery({
 66→    queryKey: ['feed', user?.id],
 67→    queryFn: ({pageParam}) =>
 68→      mobileApi.getJournals(pageParam ?? null, PAGE_SIZE, user?.id),
 69→    initialPageParam: null as string | null,
 70→    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
 71→  });
 72→
 73→  const reactionMutation = useMutation({
 74→    mutationFn: async ({
 75→      journalId,
 76→      receiverId,
 77→      reactionType,
 78→    }: {
 79→      journalId: string;
 80→      receiverId: string;
 81→      reactionType: string;
 82→    }) => {
 83→      if (!token) throw new Error('Please log in to react.');
 84→      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
 85→    },
 86→    onMutate: async ({journalId, reactionType}) => {
 87→      await queryClient.cancelQueries({queryKey: ['feed']});
 88→      const prev = queryClient.getQueryData<{pages: CursorPage<JournalItem>[]}>(
 89→        ['feed', user?.id],
 90→      );
 91→      if (prev) {
 92→        queryClient.setQueryData<{pages: CursorPage<JournalItem>[]}>(
 93→          ['feed', user?.id],
 94→          old => {
 95→            if (!old) return old;
 96→            return {
 97→              ...old,
 98→              pages: old.pages.map(page => ({
 99→                ...page,
100→                data: page.data.map(item => {
101→                  if (item.id !== journalId) return item;
102→                  const removing = item.user_reaction === reactionType;
103→                  const currentCount =
104→                    (item.reaction_count?.[0]?.count ??
105→                      item.like_count?.[0]?.count ??
106→                      item.likes_count ??
107→                      0) as number;
108→                  const delta = removing ? -1 : item.user_reaction ? 0 : 1;
109→                  return {
110→                    ...item,
111→                    user_reaction: removing ? null : reactionType,
112→                    has_liked: removing ? false : true,
113→                    like_count: [{count: Math.max(0, currentCount + delta)}],
114→                  };
115→                }),
116→              })),
117→            };
118→          },
119→        );
120→      }
121→      return {prev};
122→    },
123→    onError: (_err, _vars, context) => {
124→      if (context?.prev) {
125→        queryClient.setQueryData(['feed', user?.id], context.prev);
126→      }
127→    },
128→    onSettled: () => {
129→      queryClient.invalidateQueries({queryKey: ['feed']});
130→    },
131→  });
132→
133→  const bookmarkMutation = useBookmarkMutation(token, ['feed', user?.id]);
134→
135→  const handleReact = (journalId: string, receiverId: string, reactionType: string) => {
136→    if (!token) return;
137→    reactionMutation.mutate({journalId, receiverId, reactionType});
138→  };
139→
140→  const handleComment = (journalId: string, receiverId?: string, commentCount?: number) => {
141→    setCommentModal({postId: journalId, receiverId, commentCount: commentCount ?? 0});
142→  };
143→
144→  const handleBookmark = (journalId: string) => {
145→    bookmarkMutation.mutate(journalId);
146→  };
147→
148→  const handleRepost = (journalId: string, title?: string, authorName?: string, authorAvatar?: string) => {
149→    setRepostModal({journalId, title, authorName, authorAvatar});
150→  };
151→
152→  const posts = useMemo(
153→    () => feedQuery.data?.pages.flatMap(page => page.data ?? []) ?? [],
154→    [feedQuery.data?.pages],
155→  );
156→
157→  const onRefresh = async () => {
158→    setRefreshing(true);
159→    try {
160→      await feedQuery.refetch();
161→    } finally {
162→      setRefreshing(false);
163→    }
164→  };
165→
166→  const handleQuickAction = (key: string) => {
167→    if (key === 'canvas') {
168→      navigation.navigate('Canvas');
169→    } else if (key === 'universe') {
170→      navigation.navigate('Universe');
171→    } else {
172→      setActiveFilter(key);
173→    }
174→  };
175→
176→  return (
177→    <SafeAreaView
178→      style={[styles.safe, {backgroundColor: colors.bgPrimary}]}
179→      edges={['top']}>
180→      {/* Branded header */}
181→      <View
182→        style={[
183→          styles.header,
184→          {borderBottomColor: colors.borderCard},
185→        ]}>
186→        <Text style={[styles.brandText, {color: colors.textHeading}]}>
187→          iskrib
188→        </Text>
189→      </View>
190→
191→      {/* Filter chips */}
192→      <View style={styles.chipRow}>
193→        <ScrollView
194→          horizontal
195→          showsHorizontalScrollIndicator={false}
196→          contentContainerStyle={styles.chipScroll}>
197→          {QUICK_ACTIONS.map(action => (
198→            <Chip
199→              key={action.key}
200→              label={action.label}
201→              active={activeFilter === action.key}
202→              onPress={() => handleQuickAction(action.key)}
203→            />
204→          ))}
205→        </ScrollView>
206→      </View>
207→
208→      {/* Feed */}
209→      <FlatList
210→        data={posts}
211→        onRefresh={onRefresh}
212→        refreshing={refreshing}
213→        onEndReachedThreshold={0.25}
214→        onEndReached={() => {
215→          if (feedQuery.hasNextPage && !feedQuery.isFetchingNextPage) {
216→            feedQuery.fetchNextPage();
217→          }
218→        }}
219→        contentContainerStyle={styles.listContent}
220→        showsVerticalScrollIndicator={false}
221→        ListEmptyComponent={
222→          feedQuery.isLoading ? (
223→            <View style={styles.skeletonList}>
224→              <PostCardSkeleton />
225→              <PostCardSkeleton />
226→              <PostCardSkeleton />
227→            </View>
228→          ) : (
229→            <EmptyState
230→              title="No posts yet"
231→              subtitle="Pull to refresh or create your first journal post."
232→            />
233→          )
234→        }
235→        ListFooterComponent={
236→          feedQuery.isFetchingNextPage ? (
237→            <View style={styles.loadingMore}>
238→              <PostCardSkeleton />
239→            </View>
240→          ) : null
241→        }
242→        keyExtractor={item => item.id}
243→        renderItem={({item}) => {
244→          const preview = extractPlainText(item.content).slice(0, 180);
245→          const likeCount = resolveCount(
246→            item.like_count,
247→            item.likes_count,
248→          );
249→          const commentCount = resolveCount(
250→            item.comment_count,
251→            item.comments_count,
252→          );
253→          const bookmarkCount = resolveCount(item.bookmark_count);
254→          const bannerImage = extractBannerImage(
255→            item.content,
256→            (item as any).images,
257→          );
258→
259→          const receiverId = item.user_id ?? item.users?.id ?? '';
260→
261→          const handleAuthorPress = () => {
262→            const authorId = item.users?.id ?? item.user_id;
263→            if (!authorId) return;
264→            if (authorId === user?.id) {
265→              navigation.navigate('Main' as any, {screen: 'Profile'});
266→            } else {
267→              navigation.navigate('VisitProfile', {
268→                userId: authorId,
269→                username: item.users?.username ?? undefined,
270→              });
271→            }
272→          };
273→
274→          const isRepost = !!item.is_repost;
275→          const repostSource = isRepost ? item.repost_source : null;
276→          const repostSourcePreview = repostSource?.content
277→            ? extractPlainText(repostSource.content).slice(0, 180)
278→            : '';
279→
280→          return (
281→            <PostCard
282→              title={item.title || 'Untitled Post'}
283→              bodyPreview={preview || 'No preview text available.'}
284→              authorName={item.users?.name || 'Unknown author'}
285→              authorAvatar={item.users?.image_url}
286→              authorBadge={item.users?.badge as 'legend' | 'og' | undefined}
287→              bannerImage={bannerImage}
288→              postType={item.post_type}
289→              likeCount={likeCount}
290→              commentCount={commentCount}
291→              bookmarkCount={bookmarkCount}
292→              userReaction={item.user_reaction}
293→              isBookmarked={!!item.has_bookmarked}
294→              onReact={type => handleReact(item.id, receiverId, type)}
295→              onComment={() => handleComment(item.id, receiverId, commentCount)}
296→              onBookmark={() => handleBookmark(item.id)}
297→              onRepost={() => handleRepost(item.id, item.title ?? undefined, item.users?.name ?? undefined, item.users?.image_url ?? undefined)}
298→              onPress={() =>
299→                navigation.navigate('PostDetail', {journalId: item.id})
300→              }
301→              onAuthorPress={handleAuthorPress}
302→              isRepost={isRepost}
303→              repostCaption={item.repost_caption}
304→              repostSourceTitle={repostSource?.title}
305→              repostSourcePreview={repostSourcePreview}
306→              repostSourceAuthorName={repostSource?.users?.name}
307→              repostSourceAuthorAvatar={repostSource?.users?.image_url}
308→              onEmbeddedPress={repostSource ? () => navigation.navigate('PostDetail', {journalId: repostSource.id}) : undefined}
309→            />
310→          );
311→        }}
312→        ItemSeparatorComponent={() => <View style={styles.separator} />}
313→      />
314→
315→      {commentModal && (
316→        <CommentModal
317→          visible
318→          postId={commentModal.postId}
319→          receiverId={commentModal.receiverId}
320→          commentCount={commentModal.commentCount}
321→          onClose={() => setCommentModal(null)}
322→        />
323→      )}
324→
325→      {repostModal && (
326→        <RepostModal
327→          visible
328→          sourceJournalId={repostModal.journalId}
329→          title={repostModal.title}
330→          authorName={repostModal.authorName}
331→          authorAvatar={repostModal.authorAvatar}
332→          onClose={() => setRepostModal(null)}
333→        />
334→      )}
335→
336→      {/* FAB Write Button */}
337→      <Pressable
338→        onPress={() => navigation.navigate('JournalEditor', {mode: 'create'})}
339→        style={({pressed}) => [
340→          styles.fab,
341→          {backgroundColor: colors.accentAmber},
342→          shadows(colors).elevated,
343→          pressed && styles.fabPressed,
344→        ]}>
345→        <PenIcon size={22} color="#1A1612" />
346→      </Pressable>
347→    </SafeAreaView>
348→  );
349→}
350→
351→const styles = StyleSheet.create({
352→  safe: {
353→    flex: 1,
354→  },
355→  header: {
