 3→export const extractPlainText = (rawContent: string | null | undefined): string => {
 4→  if (!rawContent) return '';
 5→  try {
 6→    const parsed = JSON.parse(rawContent) as {
 7→      root?: {children?: Array<{children?: Array<{text?: string}>}>};
 8→    };
 9→    const parts: string[] = [];
10→    parsed.root?.children?.forEach(node => {
11→      node.children?.forEach(child => {
12→        if (child.text) parts.push(child.text);
13→      });
14→    });
15→    return parts.join(' ').replace(/\s+/g, ' ').trim();
16→  } catch {
17→    return rawContent.replace(/\s+/g, ' ').trim();
18→  }
19→};
