 55→    journalId: string;
 56→    title?: string;
 57→    authorName?: string;
 58→    authorAvatar?: string;
 59→  } | null>(null);
 60→
 61→  const galleryQuery = useInfiniteQuery({
 62→    queryKey: ['canvas-gallery', user?.id, sort],
 63→    queryFn: ({pageParam}) =>
 64→      mobileApi.getCanvasGallery(user?.id, PAGE_SIZE, sort, pageParam ?? null),
 65→    initialPageParam: null as string | null,
 66→    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
 67→  });
 68→
 69→  const reactionMutation = useMutation({
 70→    mutationFn: async ({
 71→      journalId,
 72→      receiverId,
 73→      reactionType,
 74→    }: {
 75→      journalId: string;
 76→      receiverId: string;
 77→      reactionType: string;
 78→    }) => {
 79→      if (!token) throw new Error('Please log in to react.');
 80→      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
 81→    },
 82→    onMutate: async ({journalId, reactionType}) => {
 83→      const qk = ['canvas-gallery', user?.id, sort];
 84→      await queryClient.cancelQueries({queryKey: qk});
 85→      const prev = queryClient.getQueryData<{pages: CursorPage<JournalItem>[]}>(qk);
 86→      if (prev) {
 87→        queryClient.setQueryData<{pages: CursorPage<JournalItem>[]}>(qk, old => {
 88→          if (!old) return old;
 89→          return {
 90→            ...old,
 91→            pages: old.pages.map(page => ({
 92→              ...page,
 93→              data: page.data.map(item => {
 94→                if (item.id !== journalId) return item;
 95→                const removing = item.user_reaction === reactionType;
 96→                const currentCount =
 97→                  (item.reaction_count?.[0]?.count ??
 98→                    item.like_count?.[0]?.count ??
 99→                    item.likes_count ??
100→                    0) as number;
101→                const delta = removing ? -1 : item.user_reaction ? 0 : 1;
102→                return {
103→                  ...item,
104→                  user_reaction: removing ? null : reactionType,
105→                  has_liked: removing ? false : true,
106→                  like_count: [{count: Math.max(0, currentCount + delta)}],
107→                };
108→              }),
109→            })),
110→          };
111→        });
112→      }
113→      return {prev};
114→    },
115→    onError: (_err, _vars, context) => {
116→      if (context?.prev) {
117→        queryClient.setQueryData(
118→          ['canvas-gallery', user?.id, sort],
119→          context.prev,
120→        );
