  1→import { useEffect, useMemo, useState } from "react";
  2→import { Image as KonvaImage, Layer, Line, Rect, Stage, Text } from "react-konva";
  3→
  4→const FONT_BRUSHES = {
  5→    serif: {fontFamily: "\"Courier New\", \"Lucida Console\", monospace", fontStyle: "normal"},
  6→    handwritten: {fontFamily: "\"Comic Sans MS\", \"Bradley Hand\", cursive", fontStyle: "normal"},
  7→    bold: {fontFamily: "\"Trebuchet MS\", \"Gill Sans\", sans-serif", fontStyle: "bold"},
  8→    serifDisplay: {fontFamily: "Georgia, \"Times New Roman\", serif", fontStyle: "normal"}
  9→};
 10→
 11→const FONT_STYLE_MAP = {
 12→    serif: "serif",
 13→    handwritten: "handwritten",
 14→    bold: "bold",
 15→    mono: "serif",
 16→    serifDisplay: "serifDisplay"
 17→};
 18→
 19→const GRID_SIZE = 24;
 20→const OBJECT_LIFT_MULTIPLIER = 1.03;
 21→const DEFAULT_DOODLE_COLOR = "#ff2d55";
 22→
 23→const clamp = (value, min, max) => Math.min(Math.max(value, min), max);
 24→
 25→const getSnippetMetrics = (snippet, stageWidth) => {
 26→    const sizeScale = Number.isFinite(snippet?.sizeScale) ? snippet.sizeScale : 1;
 27→    const styleKey = FONT_STYLE_MAP[snippet?.fontStyle] || "serif";
 28→    const baseFontSize = styleKey === "bold" ? 34 : styleKey === "handwritten" ? 32 : 30;
 29→    const fontSize = clamp(baseFontSize * sizeScale, 18, 92);
 30→    const estimatedWidth = Math.max(120, Math.min(stageWidth * 0.78, Math.round(((snippet?.text?.length || 1) * fontSize) * 0.58)));
 31→    const charsPerLine = Math.max(8, Math.floor(estimatedWidth / (fontSize * 0.56)));
 32→    const lineCount = Math.max(1, Math.ceil((snippet?.text?.length || 1) / charsPerLine));
 33→    const height = Math.max(68, Math.round(lineCount * fontSize * 1.14 + 18));
 34→
 35→    return {width: estimatedWidth, height, fontSize};
 36→};
 37→
 38→const useLoadedImage = (src) => {
 39→    const [image, setImage] = useState(null);
 40→
 41→    useEffect(() => {
 42→        if(!src){
 43→            setImage(null);
 44→            return;
 45→        }
 46→
 47→        const img = new window.Image();
 48→        img.crossOrigin = "anonymous";
 49→        img.onload = () => setImage(img);
 50→        img.onerror = () => setImage(null);
 51→        img.src = src;
 52→
 53→        return () => {
 54→            img.onload = null;
 55→            img.onerror = null;
 56→        };
 57→    }, [src]);
 58→
 59→    return image;
 60→};
 61→
 62→const CanvasImageNode = ({
 63→    canvasImage,
 64→    stageWidth,
 65→    stageHeight,
 66→    isSelected,
 67→    isDragging,
 68→    onSelect,
 69→    onDragStart,
 70→    onDragEnd,
 71→    canInteract,
 72→    preventTouchDefault,
 73→    isBeingRemoved
 74→}) => {
 75→    const loadedImage = useLoadedImage(canvasImage?.src);
 76→    const objectWidth = clamp((canvasImage?.width || 0.3) * stageWidth, 56, stageWidth * 0.95);
 77→    const objectHeight = clamp((canvasImage?.height || 0.3) * stageHeight, 56, stageHeight * 0.95);
 78→    const x = clamp((canvasImage?.x || 0) * stageWidth, 0, Math.max(0, stageWidth - objectWidth));
 79→    const y = clamp((canvasImage?.y || 0) * stageHeight, 0, Math.max(0, stageHeight - objectHeight));
 80→    const liftMultiplier = isDragging ? OBJECT_LIFT_MULTIPLIER + 0.02 : isSelected ? OBJECT_LIFT_MULTIPLIER : 1;
 81→    const baseScaleX = canvasImage?.scaleX === -1 ? -1 : 1;
 82→
 83→    return (
 84→        <>
 85→            <KonvaImage
 86→                name={canvasImage?.id}
 87→                x={x}
 88→                y={y}
 89→                width={objectWidth}
 90→                height={objectHeight}
 91→                image={loadedImage}
 92→                draggable={canInteract && !isBeingRemoved}
 93→                rotation={canvasImage?.rotation || 0}
 94→                scaleX={baseScaleX * liftMultiplier}
 95→                scaleY={liftMultiplier}
 96→                shadowColor="rgba(0,0,0,0.3)"
 97→                shadowBlur={isSelected || isDragging ? 16 : 8}
 98→                shadowOffsetY={isSelected || isDragging ? 6 : 3}
 99→                preventDefault={preventTouchDefault}
100→                onClick={canInteract ? onSelect : undefined}
101→                onTap={canInteract ? onSelect : undefined}
102→                onDragStart={onDragStart}
103→                onDragEnd={onDragEnd}
104→            />
105→            {isSelected && (
106→                <Rect
107→                    x={x}
108→                    y={y}
109→                    width={objectWidth}
110→                    height={objectHeight}
111→                    stroke="#68d391"
112→                    strokeWidth={1.7}
113→                    dash={[6, 4]}
114→                    rotation={canvasImage?.rotation || 0}
115→                    listening={false}
116→                />
117→            )}
118→        </>
119→    );
120→};
121→
122→export const getCanvasStageHeight = (width, aspectRatio) => (aspectRatio === "4:5" ? Math.round(width * 1.25) : width);
123→
124→export const buildSortedCanvasObjects = (snippets = [], images = []) => {
125→    const snippetObjects = snippets.map((snippet) => ({kind: "snippet", payload: snippet}));
126→    const imageObjects = images.map((image) => ({kind: "image", payload: image}));
127→    return [...snippetObjects, ...imageObjects].sort((a, b) => (a?.payload?.zIndex || 0) - (b?.payload?.zIndex || 0));
128→};
129→
130→const CanvasSurface = ({
131→    stageRef = null,
132→    viewportWidth,
133→    viewportHeight,
134→    stageWidth,
135→    stageHeight,
136→    fitScale = 1,
137→    fitOffsetX = 0,
138→    fitOffsetY = 0,
139→    viewport = {scale: 1, x: 0, y: 0},
140→    gridEnabled = false,
141→    theme = "light",
142→    doodles = [],
143→    isDrawing = false,
144→    currentDoodlePoints = [],
145→    doodleColor = DEFAULT_DOODLE_COLOR,
146→    doodleSize = 2.8,
147→    doodleStrokeScale = 1,
148→    sortedObjects = [],
149→    selectedObject = null,
150→    draggingObject = null,
151→    animatingRemovalId = null,
152→    canEditObjects = false,
153→    shouldPreventTouchDefault = false,
154→    activeTool = "select",
155→    className = "",
156→    children,
157→    onPointerDown,
158→    onPointerMove,
159→    onPointerUp,
160→    onStageClick,
161→    onStageTap,
162→    onSnippetSelect,
163→    onSnippetPress,
164→    onSnippetDragStart,
165→    onSnippetDragEnd,
166→    onImageSelect,
167→    onImagePress,
168→    onImageDragStart,
169→    onImageDragEnd
170→}) => {
171→    const layerTransform = useMemo(() => ({
172→        x: fitOffsetX + viewport.x,
173→        y: fitOffsetY + viewport.y,
174→        scaleX: fitScale * viewport.scale,
175→        scaleY: fitScale * viewport.scale
176→    }), [fitOffsetX, fitOffsetY, fitScale, viewport]);
177→
178→    return (
179→        <Stage
180→            ref={stageRef}
181→            width={viewportWidth}
182→            height={viewportHeight}
183→            preventDefault={activeTool === "doodle"}
184→            style={{touchAction: activeTool === "doodle" ? "none" : "pan-y"}}
185→            onMouseDown={onPointerDown}
186→            onTouchStart={onPointerDown}
187→            onMouseMove={onPointerMove}
188→            onTouchMove={onPointerMove}
189→            onMouseUp={onPointerUp}
190→            onTouchEnd={onPointerUp}
191→            onTouchCancel={onPointerUp}
192→            onMouseLeave={onPointerUp}
193→            onClick={onStageClick}
194→            onTap={onStageTap}
195→            className={className}
196→        >
197→            {gridEnabled && (
198→                <Layer listening={false} {...layerTransform} opacity={clamp((viewport.scale - 0.8) / 0.5, 0.15, 1)}>
199→                    {Array.from({length: Math.floor(stageWidth / GRID_SIZE) + 1}).map((_, index) => (
200→                        <Rect
201→                            key={`grid-v-${index}`}
202→                            x={index * GRID_SIZE}
203→                            y={0}
204→                            width={1}
205→                            height={stageHeight}
206→                            fill={theme === "dark" ? "rgba(235,235,235,0.08)" : "rgba(24,24,24,0.09)"}
207→                        />
208→                    ))}
209→                    {Array.from({length: Math.floor(stageHeight / GRID_SIZE) + 1}).map((_, index) => (
210→                        <Rect
211→                            key={`grid-h-${index}`}
212→                            x={0}
213→                            y={index * GRID_SIZE}
214→                            width={stageWidth}
215→                            height={1}
216→                            fill={theme === "dark" ? "rgba(235,235,235,0.08)" : "rgba(24,24,24,0.09)"}
217→                        />
218→                    ))}
219→                </Layer>
220→            )}
221→
222→            <Layer listening={false} {...layerTransform}>
223→                {doodles.map((doodle) => (
224→                    <Line
225→                        key={doodle.id}
226→                        points={(doodle.points || []).map((point, index) => (
227→                            index % 2 === 0 ? point * stageWidth : point * stageHeight
228→                        ))}
229→                        stroke={doodle.color || DEFAULT_DOODLE_COLOR}
230→                        strokeWidth={(Number(doodle.size) || 2.8) * doodleStrokeScale}
231→                        lineCap="round"
232→                        lineJoin="round"
233→                        tension={0.35}
234→                    />
235→                ))}
236→                {isDrawing && currentDoodlePoints.length >= 2 && (
237→                    <Line
238→                        points={currentDoodlePoints.map((point, index) => (
239→                            index % 2 === 0 ? point * stageWidth : point * stageHeight
240→                        ))}
241→                        stroke={doodleColor}
242→                        strokeWidth={doodleSize * doodleStrokeScale}
243→                        lineCap="round"
244→                        lineJoin="round"
245→                        tension={0.35}
246→                    />
247→                )}
248→            </Layer>
249→
250→            <Layer {...layerTransform}>
251→                {sortedObjects.map((object) => {
252→                    if(object.kind === "snippet"){
253→                        const snippet = object.payload;
254→                        const metrics = getSnippetMetrics(snippet, stageWidth);
255→                        const styleKey = FONT_STYLE_MAP[snippet.fontStyle] || "serif";
256→                        const brush = FONT_BRUSHES[styleKey] || FONT_BRUSHES.serif;
257→                        const snippetX = clamp(snippet.x * stageWidth, 0, Math.max(0, stageWidth - metrics.width));
258→                        const snippetY = clamp(snippet.y * stageHeight, 0, Math.max(0, stageHeight - metrics.height));
259→                        const isSelected = selectedObject?.kind === "snippet" && selectedObject?.id === snippet.id;
260→                        const isDragging = draggingObject?.kind === "snippet" && draggingObject?.id === snippet.id;
261→                        const liftMultiplier = isDragging ? OBJECT_LIFT_MULTIPLIER + 0.02 : isSelected ? OBJECT_LIFT_MULTIPLIER : 1;
262→                        const baseScaleX = snippet.scaleX === -1 ? -1 : 1;
263→
264→                        return (
265→                            <Text
266→                                key={snippet.id}
267→                                name={snippet.id}
268→                                x={snippetX}
269→                                y={snippetY}
270→                                width={metrics.width}
271→                                height={metrics.height}
272→                                text={snippet.text}
273→                                fontFamily={brush.fontFamily}
274→                                fontStyle={brush.fontStyle}
275→                                fontSize={metrics.fontSize}
276→                                fill={theme === "dark" ? "#f8f7f1" : "#151513"}
277→                                align="center"
278→                                verticalAlign="middle"
279→                                padding={8}
280→                                wrap="word"
281→                                draggable={canEditObjects}
282→                                rotation={snippet.rotation || 0}
283→                                scaleX={baseScaleX * liftMultiplier}
284→                                scaleY={liftMultiplier}
285→                                stroke={isSelected ? "#68d391" : "transparent"}
286→                                strokeWidth={isSelected ? 1.2 : 0}
