**Step 4 — New file `apps/mobile/src/components/CanvasPreview/CanvasPreview.tsx`**

This is the core new component. Structure:

```typescript
import React, {useMemo} from 'react';
import {Image, StyleSheet, Text, View} from 'react-native';
import Svg, {Polyline} from 'react-native-svg';
import type {CanvasDoc, CanvasSnippet, CanvasImage, CanvasDoodle} from '../../lib/api/mobileApi';
import {fonts} from '../../theme/typography';

const PREVIEW_HEIGHT = 180; // matches banner height
const LOGICAL_STAGE_WIDTH = 560;

// Font mapping (web fontStyle → app font)
const CANVAS_FONT_MAP: Record<string, string> = {
  handwritten: fonts.brand.semiBoldItalic,
  serif: fonts.serif.regular,
  mono: fonts.serif.regular,
  bold: fonts.ui.bold,
  serifDisplay: fonts.brand.semiBold,
};

const FONT_STYLE_KEY_MAP: Record<string, string> = {
  serif: 'serif',
  handwritten: 'handwritten',
  bold: 'bold',
  mono: 'serif',
  serifDisplay: 'serifDisplay',
};

function clamp(val: number, min: number, max: number): number {
  return Math.min(Math.max(val, min), max);
}

function getSnippetFontSize(snippet: CanvasSnippet, previewWidth: number): number {
  const sizeScale = Number.isFinite(snippet.sizeScale) ? (snippet.sizeScale ?? 1) : 1;
  const styleKey = FONT_STYLE_KEY_MAP[snippet.fontStyle ?? 'serif'] ?? 'serif';
  const baseFontSize = styleKey === 'bold' ? 34 : styleKey === 'handwritten' ? 32 : 30;
  const scaleFactor = previewWidth / LOGICAL_STAGE_WIDTH;
  return clamp(baseFontSize * sizeScale * scaleFactor, 6, 48);
}

interface CanvasPreviewProps {
  canvasDoc: CanvasDoc | string | null | undefined;
  width: number;  // pixel width of the card — caller passes this
}

export function CanvasPreview({canvasDoc, width}: CanvasPreviewProps) {
  const doc = useMemo<CanvasDoc | null>(() => {
    if (!canvasDoc) return null;
    if (typeof canvasDoc === 'string') {
      try { return JSON.parse(canvasDoc); } catch { return null; }
    }
    return canvasDoc;
  }, [canvasDoc]);

  const meta = doc?.meta;
  const snippets: CanvasSnippet[] = doc?.snippets ?? [];
  const images: CanvasImage[] = doc?.images ?? [];
  const doodles: CanvasDoodle[] = doc?.doodles ?? [];

  const isDark = meta?.theme === 'dark';
  const aspectRatio = meta?.aspectRatio === '4:5' ? (4 / 5) : 1;
  const previewHeight = Math.min(PREVIEW_HEIGHT, Math.round(width * (1 / aspectRatio)));

  const textColor = isDark ? '#f8f7f1' : '#151513';
  const bgColor = isDark ? '#1A1A1A' : '#FAFAFA';

  // Sort all objects by zIndex for correct layering
  const sortedImages = useMemo(
    () => [...images].sort((a, b) => (a.zIndex ?? 0) - (b.zIndex ?? 0)),
    [images],
  );
  const sortedSnippets = useMemo(
    () => [...snippets].sort((a, b) => (a.zIndex ?? 0) - (b.zIndex ?? 0)),
    [snippets],
  );

  return (
    <View style={[styles.container, {width, height: previewHeight, backgroundColor: bgColor}]}>
      {/* Images layer */}
      {sortedImages.map(img => {
        const imgW = clamp(img.width * width, 20, width);
        const imgH = clamp(img.height * previewHeight, 20, previewHeight);
        const imgX = clamp(img.x * width, 0, width - imgW);
        const imgY = clamp(img.y * previewHeight, 0, previewHeight - imgH);
        return (
          <Image
            key={img.id}
            source={{uri: img.src}}
            style={[styles.absoluteItem, {
              left: imgX,
              top: imgY,
              width: imgW,
              height: imgH,
              transform: [{rotate: `${img.rotation ?? 0}deg`},
                          {scaleX: img.scaleX === -1 ? -1 : 1}],
            }]}
            resizeMode="cover"
          />
        );
      })}

      {/* Text/snippet layer */}
      {sortedSnippets.map(snippet => {
        const fontSize = getSnippetFontSize(snippet, width);
        const snippetW = Math.min(width * 0.78, Math.max(60, snippet.text.length * fontSize * 0.4));
        const snippetX = clamp(snippet.x * width, 0, width - snippetW);
        const snippetY = clamp(snippet.y * previewHeight, 0, previewHeight - fontSize * 1.5);
        const fontFamily = CANVAS_FONT_MAP[snippet.fontStyle ?? 'serif'] ?? fonts.serif.regular;
        return (
          <Text
            key={snippet.id}
            numberOfLines={4}
            style={[styles.absoluteItem, {
              left: snippetX,
              top: snippetY,
              width: snippetW,
              fontSize,
              fontFamily,
              color: textColor,
              transform: [{rotate: `${snippet.rotation ?? 0}deg`},
                          {scaleX: snippet.scaleX === -1 ? -1 : 1}],
            }]}
          >
            {snippet.text}
          </Text>
        );
      })}

      {/* Doodle SVG overlay */}
      {doodles.length > 0 && (
        <Svg
          style={StyleSheet.absoluteFill}
          width={width}
          height={previewHeight}
          pointerEvents="none">
          {doodles.map(doodle => {
            const pts = doodle.points
              .map((p, i) => (i % 2 === 0 ? p * width : p * previewHeight))
              .join(',');
            return (
              <Polyline
                key={doodle.id}
                points={pts}
                stroke={doodle.color ?? '#ff2d55'}
                strokeWidth={Math.max(1, (doodle.size ?? 2.8) * (width / LOGICAL_STAGE_WIDTH))}
                strokeLinecap="round"
                strokeLinejoin="round"
                fill="none"
              />
            );
          })}
        </Svg>
      )}
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    overflow: 'hidden',
  },
  absoluteItem: {
    position: 'absolute',
  },
});
```

Note: The layering is images first, then snippets on top. The web sorts by `zIndex` across both types together (via `buildSortedCanvasObjects`). If cross-type z-ordering is important (e.g., a snippet under an image), a more faithful approach would merge the arrays and sort by zIndex, then render each element with a `zIndex` style prop on the `View`. However, since this is a read-only preview, the simplified split-layer approach is acceptable and avoids the complexity of conditional rendering branching inside a sorted map.

If cross-type z-ordering must be exact, the merge pattern looks like this:

```typescript
const allObjects = useMemo(() => {
  const withKind = [
    ...images.map(i => ({kind: 'image' as const, zIndex: i.zIndex ?? 0, payload: i})),
    ...snippets.map(s => ({kind: 'snippet' as const, zIndex: s.zIndex ?? 0, payload: s})),
  ].sort((a, b) => a.zIndex - b.zIndex);
  return withKind;
}, [images, snippets]);
```

Then render `allObjects.map(obj => obj.kind === 'image' ? <Image .../> : <Text .../>)` with an explicit `style.zIndex` set to the object's zIndex value. This exactly mirrors `buildSortedCanvasObjects` from the web.

**Step 5 — `apps/mobile/src/screens/Advanced/CanvasScreen.tsx`**

Wire it all together. Changes:

1. Import `CanvasPreview` and `getCanvasPlainText` and `parseCanvasDoc`.
2. Import `useWindowDimensions` from React Native.
3. In `renderItem`, compute:
   - `const cardWidth = windowWidth - spacing.lg * 2;` (matches `listContent.paddingHorizontal`)
   - `const canvasDoc = parseCanvasDoc(item.canvas_doc);`
   - `const isEmpty = !canvasDoc?.snippets?.length && !canvasDoc?.images?.length && !canvasDoc?.doodles?.length;`
   - `const preview = getCanvasPlainText(item.canvas_doc).slice(0, 180);` (replaces `extractPlainText(item.content)`)
   - `const bannerContent = isEmpty ? undefined : <CanvasPreview canvasDoc={item.canvas_doc} width={cardWidth} />;`
4. Pass `bannerContent={bannerContent}` to `PostCard` (instead of `bannerImage`).
5. Remove the `extractBannerImage` call (canvas posts have no Lexical-embedded images).
6. Change `bodyPreview` to use `preview` (from `getCanvasPlainText`).

The `bodyPreview` prop keeps the existing fallback `|| 'No preview text available.'` for posts with no snippets and no images.

---

### Trade-off Summary

| Concern | Decision | Trade-off Accepted |
|---|---|---|
| Banner slot | `bannerContent` prop on PostCard | Minimal PostCard change; no layout restructuring |
| Render strategy | Option A (View + SVG) | Slightly less faithful doodle curves (SVG Polyline vs Konva Line tension:0.35); simpler and uses already-proven SVG import |
| Font matching | Map to app's bundled fonts | Not pixel-perfect vs. web; avoids missing-font crashes |
| Z-ordering | Simplified split-layer (images then snippets) | Images always under text; good enough for preview |
| Font size scaling | `width / 560` scale factor applied to web base sizes | Correct proportional rendering at preview width |
| Empty state | No banner rendered | Clean degradation; avoids dead gray rectangle |
| Width measurement | Caller computes `windowWidth - padding` and passes as prop | Avoids async `onLayout` round-trip and re-render; deterministic on first render |

---

### Potential Challenges

1. **`canvas_doc` arriving as a string vs. object.** The Supabase JS client v2 returns JSONB columns as parsed objects. The v1 client returned strings. Since the mobile app uses `@supabase/supabase-js@^2.97.0` but routes through a custom REST API (`apiRequest`), the data shape depends on what the server sends. The server's `getService.js` shapes the RPC response manually, setting `canvas_doc: row.canvas_doc` — which is whatever Postgres/Supabase returns. The safe approach is to always handle both `string` and `object` in `parseCanvasDoc`.

2. **Image rotation transform origin.** React Native `transform: rotate` pivots around the center of the element. The web Konva canvas also rotates around the element's registration point (top-left by default with `x/y` already computed). For thumbnails this difference is acceptable.

3. **`scaleX: -1` (horizontal flip) combined with rotation.** The `transform` array order matters: `[{rotate}, {scaleX: -1}]` and `[{scaleX: -1}, {rotate}]` produce different results. The web applies scaleX to the Konva node, which is a matrix operation separate from rotation. In RN, put `scaleX` after `rotate` in the array to get closest equivalence.

4. **Doodle stroke width.** The web's Konva `doodleStrokeScale` is a separate multiplier (defaults to 1 in preview). The `size` field in the doodle (1–14px at 560px stage) should scale to `size * (previewWidth / 560)` for proportional rendering at preview size. Minimum 1px.

5. **`FlatList` and many image renders.** Each canvas card can have multiple `<Image>` children for remote URIs. If many canvas posts are loaded (pageSize is 10), this could create 40–50 remote image loads simultaneously. This is mitigated by React Native's built-in image caching and the FlatList's `windowSize` prop which recycles off-screen cells.

---

### Critical Files for Implementation

- `C:/Users/johnm/iskrib_mobile_app/apps/mobile/src/lib/api/mobileApi.ts` — Add `canvas_doc` field and all `CanvasDoc` types to `JournalItem`; this is the foundation everything else depends on
- `C:/Users/johnm/iskrib_mobile_app/apps/mobile/src/components/PostCard/PostCard.tsx` — Add `bannerContent?: React.ReactNode` prop and update the banner render branch
- `C:/Users/johnm/iskrib_mobile_app/apps/mobile/src/components/CanvasPreview/CanvasPreview.tsx` — New file to create; the core visual preview component using RN View + SVG
- `C:/Users/johnm/iskrib_mobile_app/apps/mobile/src/lib/utils/journalHelpers.ts` — Add `parseCanvasDoc` and `getCanvasPlainText` helpers
- `C:/Users/johnm/iskrib_mobile_app/apps/mobile/src/screens/Advanced/CanvasScreen.tsx` — Wire everything together: read `canvas_doc`, compute preview text and banner content, pass to PostCard

